INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2023/09/22 14:59:59", 0.0, 1, 1.47, "クローチェ", 1, 126401, 1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 2002, 10001, "2023/06/30 12:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2023/09/22 14:59:59", 0.0, 2, 2.15, "クローチェ", 1, 126401, 2, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 2002, 10002, "2023/06/30 12:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2023/09/22 14:59:59", 0.0, 2, 0.0, "ライラエル", 1, 126501, 1, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 2002, 10003, "2023/06/30 12:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2023/09/22 14:59:59", 0.0, 1, 0.0, "ライラエル", 1, 126501, 2, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 2002, 10004, "2023/06/30 12:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2023/12/22 14:59:59", 0.0, 2, 0.0, "リンド", 2, 127702, 1, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 2002, 10005, "2023/09/15 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2023/12/22 14:59:59", 0.0, 2, 0.0, "リンド", 2, 127702, 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 2002, 10006, "2023/09/15 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2023/12/22 14:59:59", 0.0, 1, 0.0, "ヴルム", 2, 127802, 1, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 2002, 10007, "2023/09/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2023/12/22 14:59:59", 0.0, 2, 6.5, "ヴルム", 2, 127802, 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 2002, 10008, "2023/09/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/03/22 14:59:59", 0.0, 2, 0.0, "アネモネ", 3, 129602, 1, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 2002, 10009, "2023/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/03/22 14:59:59", 0.0, 2, 0.0, "アネモネ", 3, 129602, 2, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 2002, 10010, "2023/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/03/22 14:59:59", 0.0, 1, 0.0, "ネフィ=ネラ", 3, 129701, 1, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 2002, 10011, "2023/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/03/22 14:59:59", 0.0, 2, 6.2, "ネフィ=ネラ", 3, 129701, 2, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 2002, 10012, "2023/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/06/22 14:59:59", 0.0, 3, 3.1, "カノン", 4, 130301, 1, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 2002, 10013, "2024/03/15 15:00:00", 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/06/22 14:59:59", 0.0, 3, 6.15, "カノン", 4, 130301, 2, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 2002, 10014, "2024/03/15 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/06/22 14:59:59", 0.0, 2, 0.0, "ナーナ", 4, 130401, 1, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 2002, 10015, "2024/03/15 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/06/22 14:59:59", 0.0, 2, 3.35, "ナーナ", 4, 130401, 2, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 2002, 10016, "2024/03/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/09/22 14:59:59", 0.0, 1, 0.0, "ホウオウ", 5, 130502, 1, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 2002, 10017, "2024/06/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/09/22 14:59:59", 0.0, 2, 3.18, "ホウオウ", 5, 130502, 2, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 2002, 10018, "2024/06/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/09/22 14:59:59", 0.0, 4, 0.0, "ホウオウ", 5, 130503, 3, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 2002, 10019, "2024/06/15 15:00:00", 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/09/22 14:59:59", 0.0, 1, 4.9, "ネア", 5, 123301, 1, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 2002, 10020, "2024/06/15 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/09/22 14:59:59", 0.0, 1, 4.8, "ネア", 5, 123301, 2, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 2002, 10021, "2024/06/15 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/12/22 14:59:59", 0.0, 3, 4.922, "カリザ", 6, 133301, 1, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 2002, 10022, "2024/09/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/12/22 14:59:59", 0.0, 3, 9.638, "カリザ", 6, 133301, 2, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 2002, 10023, "2024/09/15 15:00:00", 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/12/22 14:59:59", 0.0, 1, 2.88, "ミーア", 6, 133401, 1, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2002, 10024, "2024/09/15 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2024/12/22 14:59:59", 0.0, 5, 4.818, "ミーア", 6, 133401, 2, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 2002, 10025, "2024/09/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/03/22 14:59:59", 0.0, 2, 1.78, "グレイス", 7, 133002, 1, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 2002, 10026, "2024/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/03/22 14:59:59", 0.0, 1, 6.15, "グレイス", 7, 133002, 2, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 2002, 10027, "2024/12/15 15:00:00", 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/03/22 14:59:59", 0.0, 6, 4.28, "ヴァイオレット", 7, 133102, 1, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 2002, 10028, "2024/12/15 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/03/22 14:59:59", 0.0, 1, 0.0, "ヴァイオレット", 7, 133102, 2, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 2002, 10029, "2024/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/06/23 14:59:59", 0.0, 2, 5.53, "ルルィ", 8, 136902, 1, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 2002, 10030, "2025/03/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/06/23 14:59:59", 0.0, 9, 6.05, "ルルィ", 8, 136902, 2, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 2002, 10031, "2025/03/15 15:00:00", 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/06/23 14:59:59", 0.0, 2, 0.0, "デュラン", 8, 137001, 1, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 2002, 10032, "2025/03/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/06/23 14:59:59", 0.0, 2, 0.0, "デュラン", 8, 137001, 2, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 2002, 10033, "2025/03/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/09/23 14:59:59", 0.0, 2, 0.0, "サツキ", 9, 135902, 1, "おう\n好きなもん持ってきな", 2002, 10034, "2025/06/16 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/09/23 14:59:59", 0.0, 1, 4.935, "サツキ", 9, 135902, 2, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 2002, 10035, "2025/06/16 15:00:00", 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/09/23 14:59:59", 0.0, 2, 7.441, "ユキノ", 9, 135802, 1, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 2002, 10036, "2025/06/16 15:00:00", 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/09/23 14:59:59", 0.0, 7, 0.0, "ユキノ", 9, 135802, 2, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 2002, 10037, "2025/06/16 15:00:00", 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/12/22 14:59:59", 0.0, 2, 2.295, "クルル", 10, 130901, 1, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2002, 10038, "2025/09/16 15:00:00", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/12/22 14:59:59", 0.0, 1, 6.281, "クルル", 10, 130901, 2, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 2002, 10039, "2025/09/16 15:00:00", 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/12/22 14:59:59", 0.0, 2, 5.549, "ヴォルガーノ", 10, 137701, 1, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 2002, 10040, "2025/09/16 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2025/12/22 14:59:59", 0.0, 3, 2.64, "ヴォルガーノ", 10, 137701, 2, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2002, 10041, "2025/09/16 15:00:00", 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2026/03/23 11:59:59", 0.0, 7, 7.642, "ライラエル", 11, 132801, 1, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 2002, 10042, "2025/12/15 15:00:00", 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2026/03/23 11:59:59", 0.0, 1, 0.0, "ライラエル", 11, 132802, 2, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 2002, 10043, "2025/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2026/03/23 11:59:59", 0.0, 1, 0.0, "クローチェ", 11, 134502, 1, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 2002, 10044, "2025/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2026/03/23 11:59:59", 0.0, 2, 3.72, "クローチェ", 11, 134501, 2, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 2002, 10045, "2025/12/15 15:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2026/06/22 11:59:59", 0.0, 2, 4.991, "ネフィ＝ネラ", 12, 138201, 1, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 2002, 10046, "2026/03/16 12:00:00", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2026/06/22 11:59:59", 0.0, 1, 3.877, "ネフィ＝ネラ", 12, 138201, 2, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 2002, 10047, "2026/03/16 12:00:00", 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2026/06/22 11:59:59", 0.0, 4, 1.71, "アラクネ", 12, 136001, 1, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 2002, 10048, "2026/03/16 12:00:00", 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, "2026/06/22 11:59:59", 0.0, 5, 5.32, "アラクネ", 12, 136001, 2, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 2002, 10049, "2026/03/16 12:00:00", 2);
